// 完整 printExp.html：从静态资源 /printExp.html 加载（需 staticDirs: ['..']）
export const PrintExpFull = {
  name: '完整 printExp.html',
  render: (args, { argTypes }) => ({
    components: { HgPrintBlock: Component },
    props: Object.keys(argTypes),
    data: () => ({ printExpHtml: PRINT_EXP_HTML, loading: true, error: '' }),
    mounted() {
      fetch('/printExp.html')
        .then((r) => (r.ok ? r.text() : Promise.reject(new Error(r.statusText))))
        .then((html) => {
          this.printExpHtml = html;
          this.loading = false;
        })
        .catch((e) => {
          this.error = '未加载到 printExp.html，当前为精简示例。';
          this.loading = false;
        });
    },
    template: `
      <div class="print-exp-story">
        <div style="margin-bottom: 12px; display: flex; align-items: center; gap: 12px; flex-wrap: wrap;">
          <button type="button" @click="$refs.block && $refs.block.print()" style="padding: 6px 14px; cursor: pointer;">导出并打印 PDF</button>
          <span v-if="loading" style="color: #999;">加载 printExp.html 中…</span>
          <span v-else-if="error" style="color: #f66;">{{ error }}</span>
          <span v-else style="color: #666; font-size: 14px;">已加载完整 printExp.html</span>
        </div>
        <hg-print-block ref="block" v-bind="$props" print-direction="vertical" :y-border="10" :x-border="10">
          <div class="print-exp-slot" v-html="printExpHtml" style="width: 100%; box-sizing: border-box;"></div>
        </hg-print-block>
      </div>
    `,
  }),
  args: {
    printDirection: 'vertical',
    hideOnScreen: false,
    debug: false,
  },
};
